#[panic_handler]
/// panic handler
fn panic(info: &PanicInfo) -> ! {
    hal::util::backtrace();
    if let Some(location) = info.location() {
        error!(
            "[kernel] Panicked at {}:{} {}",
            location.file(),
            location.line(),
            info.message()
        );
    } else {
        error!("[kernel] Panicked: {}", info.message());
    }
    unsafe { Instruction::shutdown(true) }
}

